<?php
require __DIR__.'/../includes/bootstrap.php';require_admin();if(!brands_schema_ready())redirect('../upgrade-brands-imports.php');$preview=$_SESSION['import_preview']??null;$error='';
if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();$action=$_POST['action']??'upload';try{
 if($action==='upload'){
  if(empty($_FILES['import_file']['name'])||($_FILES['import_file']['error']??1)!==UPLOAD_ERR_OK)throw new RuntimeException('Choose a CSV file.');
  $ext=strtolower(pathinfo($_FILES['import_file']['name'],PATHINFO_EXTENSION));if(!in_array($ext,['csv','tsv'],true))throw new RuntimeException('This foundation currently accepts CSV or TSV files.');
  $rows=csv_rows($_FILES['import_file']['tmp_name']);if(!$rows)throw new RuntimeException('The file contains no data rows.');if(count($rows)>5000)throw new RuntimeException('Import files are limited to 5,000 rows per batch.');
  $entity=$_POST['entity_type']??'';if(!in_array($entity,['company','brand'],true))throw new RuntimeException('Choose an import type.');
  $_SESSION['import_preview']=['entity'=>$entity,'filename'=>basename($_FILES['import_file']['name']),'rows'=>$rows];$preview=$_SESSION['import_preview'];
 } elseif($action==='cancel'){unset($_SESSION['import_preview']);redirect('imports.php');}
 elseif($action==='rollback'){
  $batchId=(int)($_POST['batch_id']??0);if($batchId<1)throw new RuntimeException('Invalid import batch.');
  $pdo=db();$pdo->beginTransaction();
  $q=$pdo->prepare('SELECT * FROM import_batches WHERE id=? FOR UPDATE');$q->execute([$batchId]);$batchRow=$q->fetch();
  if(!$batchRow)throw new RuntimeException('Import batch not found.');
  if($batchRow['status']==='rolled_back')throw new RuntimeException('This batch has already been rolled back.');
  $q=$pdo->prepare("SELECT entity_id FROM import_items WHERE batch_id=? AND action='imported' AND entity_id IS NOT NULL");$q->execute([$batchId]);$ids=array_map('intval',$q->fetchAll(PDO::FETCH_COLUMN));
  $deleted=0;
  if($ids){$marks=implode(',',array_fill(0,count($ids),'?'));$table=$batchRow['entity_type']==='brand'?'brands':'companies';$d=$pdo->prepare("DELETE FROM {$table} WHERE id IN ({$marks}) AND import_batch_id=?");$d->execute(array_merge($ids,[$batchId]));$deleted=$d->rowCount();}
  $pdo->prepare("UPDATE import_batches SET status='rolled_back' WHERE id=?")->execute([$batchId]);$pdo->commit();
  flash('success',$deleted.' imported record(s) removed. Updated records were left unchanged.');redirect('imports.php?batch='.$batchId);
 }
 elseif($action==='run'){
  if(!$preview)throw new RuntimeException('Upload a file first.');$dup=in_array($_POST['duplicate_action']??'skip',['skip','update'],true)?$_POST['duplicate_action']:'skip';$pdo=db();$pdo->beginTransaction();$pdo->prepare('INSERT INTO import_batches(entity_type,original_filename,duplicate_action,total_rows,imported_by) VALUES(?,?,?,?,?)')->execute([$preview['entity'],$preview['filename'],$dup,count($preview['rows']),(int)user()['id']]);$batch=(int)$pdo->lastInsertId();$counts=['imported'=>0,'updated'=>0,'skipped'=>0,'error'=>0];
  foreach($preview['rows'] as $i=>$row){$rowNo=$i+2;$entityId=null;$act='error';$message='';try{
   if($preview['entity']==='company'){
    $name=trim($row['name']??$row['company_name']??'');if($name==='')throw new RuntimeException('Missing company name.');$s=$pdo->prepare('SELECT id FROM companies WHERE LOWER(name)=LOWER(?) LIMIT 1');$s->execute([$name]);$existing=$s->fetchColumn();if($existing){$entityId=(int)$existing;if($dup==='skip'){$act='skipped';$message='Duplicate company name.';}else{$pdo->prepare('UPDATE companies SET short_description=?,description=?,website=?,public_email=?,location=?,category=?,founded_year=? WHERE id=?')->execute([trim($row['short_description']??''),trim($row['description']??''),trim($row['website']??''),trim($row['public_email']??$row['email']??''),trim($row['location']??''),trim($row['category']??''),((int)($row['founded_year']??0))?:null,$entityId]);$act='updated';}}else{$slug=company_slug($name);$pdo->prepare("INSERT INTO companies(name,slug,short_description,description,website,public_email,location,category,founded_year,status,submitted_by,import_batch_id) VALUES(?,?,?,?,?,?,?,?,?,'draft',?,?)")->execute([$name,$slug,trim($row['short_description']??''),trim($row['description']??''),trim($row['website']??''),trim($row['public_email']??$row['email']??''),trim($row['location']??''),trim($row['category']??''),((int)($row['founded_year']??0))?:null,(int)user()['id'],$batch]);$entityId=(int)$pdo->lastInsertId();$act='imported';}}
   else{$name=trim($row['name']??$row['brand_name']??'');$companyName=trim($row['company_name']??$row['parent_company']??'');if($name===''||$companyName==='')throw new RuntimeException('Brand name and company_name are required.');$s=$pdo->prepare("SELECT id FROM companies WHERE LOWER(name)=LOWER(?) AND status IN ('approved','draft') LIMIT 1");$s->execute([$companyName]);$companyId=(int)$s->fetchColumn();if(!$companyId)throw new RuntimeException('Parent company not found: '.$companyName);$s=$pdo->prepare('SELECT id FROM brands WHERE company_id=? AND LOWER(name)=LOWER(?) LIMIT 1');$s->execute([$companyId,$name]);$existing=$s->fetchColumn();if($existing){$entityId=(int)$existing;if($dup==='skip'){$act='skipped';$message='Duplicate brand under this company.';}else{$pdo->prepare('UPDATE brands SET short_description=?,description=?,website=?,public_email=?,category=?,founded_year=? WHERE id=?')->execute([trim($row['short_description']??''),trim($row['description']??''),trim($row['website']??''),trim($row['public_email']??$row['email']??''),trim($row['category']??''),((int)($row['founded_year']??0))?:null,$entityId]);$act='updated';}}else{$slug=brand_slug($name);$pdo->prepare("INSERT INTO brands(company_id,name,slug,short_description,description,website,public_email,category,founded_year,status,submitted_by,import_batch_id) VALUES(?,?,?,?,?,?,?,?,?,'draft',?,?)")->execute([$companyId,$name,$slug,trim($row['short_description']??''),trim($row['description']??''),trim($row['website']??''),trim($row['public_email']??$row['email']??''),trim($row['category']??''),((int)($row['founded_year']??0))?:null,(int)user()['id'],$batch]);$entityId=(int)$pdo->lastInsertId();$act='imported';}}
  }catch(Throwable $rowError){$act='error';$message=$rowError->getMessage();}$counts[$act]++;$pdo->prepare('INSERT INTO import_items(batch_id,import_row,entity_id,action,source_key,message,row_data) VALUES(?,?,?,?,?,?,?)')->execute([$batch,$rowNo,$entityId,$act,trim($row['name']??$row['company_name']??$row['brand_name']??''),$message?:null,json_encode($row)]);
  }
  $status=$counts['error']?'completed_with_errors':'completed';$pdo->prepare('UPDATE import_batches SET status=?,imported_rows=?,updated_rows=?,skipped_rows=?,error_rows=?,completed_at=NOW() WHERE id=?')->execute([$status,$counts['imported'],$counts['updated'],$counts['skipped'],$counts['error'],$batch]);$pdo->commit();unset($_SESSION['import_preview']);flash('success',sprintf('Import complete: %d imported, %d updated, %d skipped, %d errors.',$counts['imported'],$counts['updated'],$counts['skipped'],$counts['error']));redirect('imports.php?batch='.$batch);
 }
}catch(Throwable $e){if(db()->inTransaction())db()->rollBack();$error=$e->getMessage();}}
$history=db()->query('SELECT ib.*,u.display_name FROM import_batches ib JOIN users u ON u.id=ib.imported_by ORDER BY ib.created_at DESC LIMIT 25')->fetchAll();$selected=null;$items=[];if(!empty($_GET['batch'])){$s=db()->prepare('SELECT * FROM import_batches WHERE id=?');$s->execute([(int)$_GET['batch']]);$selected=$s->fetch();if($selected){$s=db()->prepare('SELECT * FROM import_items WHERE batch_id=? ORDER BY import_row');$s->execute([(int)$selected['id']]);$items=$s->fetchAll();}}app_header('Import Center');?><section class="dashboard-hero"><p class="eyebrow">ADMINISTRATION</p><h1>Import Center</h1><p>Import companies and brands as drafts, validate each row, and keep a permanent batch report.</p></section><p class="admin-actions"><a class="button ghost" href="companies.php">Companies</a><a class="button ghost" href="brands.php">Brands</a></p><?php if($error):?><div class="alert error"><?=e($error)?></div><?php endif?><?php if(!$preview):?><form method="post" enctype="multipart/form-data" class="app-card profile-form"><?=csrf_field()?><input type="hidden" name="action" value="upload"><div class="form-grid"><label>Import type<select name="entity_type"><option value="company">Companies</option><option value="brand">Brands</option></select></label><label>CSV or TSV file<input type="file" name="import_file" accept=".csv,.tsv,text/csv" required></label></div><p class="muted">Company fields: name, short_description, description, website, public_email, location, category, founded_year. Brand files also require company_name.</p><button class="button primary">Preview Import</button></form><?php else:?><section class="app-card"><h2>Preview: <?=e($preview['filename'])?></h2><p><?=count($preview['rows'])?> rows · <?=e(ucfirst($preview['entity']))?> import · New records will be Draft.</p><div class="table-wrap"><table><thead><tr><?php foreach(array_keys($preview['rows'][0]) as $h):?><th><?=e($h)?></th><?php endforeach?></tr></thead><tbody><?php foreach(array_slice($preview['rows'],0,10) as $r):?><tr><?php foreach($r as $v):?><td><?=e((string)$v)?></td><?php endforeach?></tr><?php endforeach?></tbody></table></div><form method="post" class="admin-actions"><?=csrf_field()?><input type="hidden" name="action" value="run"><label>Duplicates <select name="duplicate_action"><option value="skip">Skip existing records</option><option value="update">Update existing records</option></select></label><button class="button primary">Run Import</button></form><form method="post"><?=csrf_field()?><button class="button ghost" name="action" value="cancel">Cancel</button></form></section><?php endif?><section class="app-card"><h2>Import History</h2><div class="table-wrap"><table><thead><tr><th>Date</th><th>Type</th><th>File</th><th>Status</th><th>Results</th></tr></thead><tbody><?php foreach($history as $h):?><tr><td><?=e($h['created_at'])?></td><td><?=e(ucfirst($h['entity_type']))?></td><td><a href="?batch=<?=(int)$h['id']?>"><?=e($h['original_filename'])?></a></td><td><?=e($h['status'])?></td><td><?=intval($h['imported_rows'])?> imported · <?=intval($h['updated_rows'])?> updated · <?=intval($h['error_rows'])?> errors</td></tr><?php endforeach?></tbody></table></div></section><?php if($selected):?><section class="app-card"><div class="section-heading"><div><h2>Batch #<?=(int)$selected['id']?> Report</h2><p class="muted">Rollback removes records created by this batch. Existing records that were updated are not changed.</p></div><?php if($selected['status']!=='rolled_back' && (int)$selected['imported_rows']>0):?><form method="post" onsubmit="return confirm('Remove records created by this import batch?');"><?=csrf_field()?><input type="hidden" name="action" value="rollback"><input type="hidden" name="batch_id" value="<?=(int)$selected['id']?>"><button class="button ghost">Rollback Imported Records</button></form><?php endif?></div><div class="table-wrap"><table><thead><tr><th>Row</th><th>Action</th><th>Source</th><th>Message</th></tr></thead><tbody><?php foreach($items as $item):?><tr><td><?=(int)$item['import_row']?></td><td><?=e($item['action'])?></td><td><?=e($item['source_key'])?></td><td><?=e($item['message'])?></td></tr><?php endforeach?></tbody></table></div></section><?php endif?><?php app_footer();
